questionvariables.text:
/* 1. Dimensions */
r: 3 + rand(3);          /* Radius: 3, 4, or 5 m */
h_cyl: 8 + rand(5);      /* Height: 8 to 12 m */
h_cone: 3 + rand(3);     /* Cone depth: 3, 4, or 5 m */
diam: 2 * r;

/* 2. Volume Calculations (pi = 3.142) */
V_cyl: %pi* r^2 * h_cyl;
V_cone: (1/3) * %pi * r^2 * h_cone;
total_m3: V_cyl + V_cone;

/* 3. Mass Calculation (Density of Maize = 750 kg/m3) */
density: 750;
total_mass_kg: total_m3 * density;
total_tonnes: total_mass_kg / 1000;

/* Teacher Answer (Rounded to 2 decimal places) */
ta: total_tonnes;

/* 4. Display Variables */
r2: r^2;
